resource "kubernetes_ingress" "ingress" {
  metadata {
    annotations = {
      "external-dns.alpha.kubernetes.io/target"            = "${local.kubernetes_namespace}-ingress-internal.meltwater.io"
      "kubernetes.io/ingress.class"                        = local.kubernetes_namespace
      "nginx.ingress.kubernetes.io/whitelist-source-range" = join(", ", concat(local.default_cidrs_to_whitelist, var.whitelisted_cidrs))
    }
    name      = "${var.browser_farm_name}-ingress"
    namespace = local.kubernetes_namespace
  }

  spec {
    dynamic "rule" {
      for_each = local.internal_hostnames_to_enable
      content {
        host = rule.value
        http {
          path {
            backend {
              service_name = var.browser_farm_name
              service_port = 80
            }
          }
        }
      }
    }
  }
}

locals {
  # azure_shared_env_dev  = "10.198.0.0/16"
  # azure_shared_env_prod = "10.199.0.0/16"
  default_cidrs_to_whitelist = concat([var.eng_vpn_cidr], var.k8s_cidrs)

  internal_hostnames_to_enable = ["${var.browser_farm_name}-${var.k8s_env_name}-internal.meltwater.io"]
}

