resource "kubernetes_deployment_v1" "main" {
  metadata {
    name      = var.browser_farm_name
    namespace = local.kubernetes_namespace
    labels = {
      app = var.browser_farm_name
    }
  }

  spec {
    selector {
      match_labels = {
        app = var.browser_farm_name
      }
    }
    # https://meltwater.atlassian.net/wiki/spaces/EE/pages/1991320452/Deployment+best+practices#1.-Best-practices-for-your-deployments-and-services
    replicas = var.replicas
    strategy {
      rolling_update { # https://meltwater.atlassian.net/wiki/spaces/EE/pages/1991320452/Deployment+best+practices#Specify-a-rolling-update-strategy
        max_surge       = "25%"
        max_unavailable = 0
      }
    }
    template {
      metadata {
        labels = {
          app = var.browser_farm_name
        }
        annotations = {
          harvest                        = var.k8s_env_name
          "logging.meltwater.io/type"    = "nested_json"
          "logging.meltwater.io/system"  = "wrty-k8s"
          "logging.meltwater.io/service" = var.browser_farm_name
          "prometheus.io/scrape"         = true
          "prometheus.io/path"           = "/metrics"
          "prometheus.io/port"           = 3002
        }
      }

      spec {
        termination_grace_period_seconds = var.termination_grace_period_seconds
        affinity {
          pod_anti_affinity {
            preferred_during_scheduling_ignored_during_execution {
              weight = 10
              pod_affinity_term {
                topology_key = "kubernetes.io/hostname"
                label_selector {
                  match_labels = {
                    app = var.browser_farm_name
                  }
                }
              }
            }
          }
        }
        # Set PAT Secret config to pull images from GitHub Registry
        image_pull_secrets {
          name = "docker-cfg"
        }
        container {
          name              = "main"
          image             = var.image
          image_pull_policy = "Always"
          command           = ["/bin/sh"]
          args              = ["-c", "ulimit -c 0; /usr/src/app/scripts/start.sh"]
          resources {
            requests = {
              cpu               = var.cpu_reservation
              memory            = var.memory_reservation
              "ephemeral-storage" = "2Gi"
            }
            limits = {
              cpu               = var.cpu_limit
              memory            = var.memory_limit
              "ephemeral-storage" = "50Gi"
            }
          }
          port {
            container_port = var.service_port
            name           = "service-port"
          }
          liveness_probe {
            http_get {
              path = "/pressure?token=${var.k8s_env_name}"
              port = 3000
            }
            initial_delay_seconds = 40
            period_seconds        = 30
            timeout_seconds       = 10
            failure_threshold     = 3
          }
          readiness_probe {
            http_get {
              path = "/ready"
              port = 3002
            }
            initial_delay_seconds = 10
            period_seconds        = 15
            timeout_seconds       = 10
            failure_threshold     = 2
            success_threshold     = 1
          }
          env_from {
            config_map_ref {
              name = kubernetes_config_map_v1.main.metadata[0].name
            }
          }
          env_from {
            secret_ref {
              name = kubernetes_secret_v1.main.metadata[0].name
            }
          }
          dynamic "lifecycle" {
            for_each = var.prestop_delay_seconds > 0 ? [var.prestop_delay_seconds] : []
            content {
              pre_stop {
                exec {
                  command = ["sh", "-c", "sleep ${lifecycle.value}"]
                }
              }
            }
          }
        }

        container {
          name              = "metrics-exporter"
          image             = var.metrics_exporter_image
          image_pull_policy = "Always"
          resources {
            requests = {
              cpu    = "500m"
              memory = "256Mi"
            }
            limits = {
              cpu    = "500m"
              memory = "512Mi"
            }
          }
          port {
            container_port = 3002
            name           = "metrics-port"
          }
          env_from {
            config_map_ref {
              name = kubernetes_config_map_v1.metrics-exporter.metadata[0].name
            }
          }
        }
      }
    }
  }
}

resource "kubernetes_config_map_v1" "main" {
  metadata {
    name      = var.browser_farm_name
    namespace = local.kubernetes_namespace
  }
  data = merge({
    "TIMEOUT"            = var.session_timeout
    "CONCURRENT"         = var.max_concurrent_sessions
    "QUEUED"             = var.max_queue_length
    "DEBUG"              = "off"
    "TOKEN"              = var.k8s_env_name
    "HEALTH"             = true  # https://docs.browserless.io/enterprise/docker/config#health--monitoring
    "MAX_MEMORY_PERCENT" = 90
    "MAX_CPU_PERCENT"    = 90
  }, var.additional_env_vars)
}

resource "kubernetes_secret_v1" "main" {
  metadata {
    name      = var.browser_farm_name
    namespace = local.kubernetes_namespace
  }
  data = var.additional_secret_env_vars
}

resource "kubernetes_config_map_v1" "metrics-exporter" {
  metadata {
    name      = "${var.browser_farm_name}-metrics-exporter"
    namespace = local.kubernetes_namespace
  }
  data = {
    "EXPORTER_HOST"          = "0.0.0.0",
    "BROWSERLESS_TOKEN"      = var.k8s_env_name,
    "READINESS_MAX_QUEUED"   = tostring(var.readiness_max_queued)
  }
}

