data "aws_kms_key" "wrapidity_key" {
  key_id = "alias/wrapidity"
}

# Secret was created manually and then imported into Terraform. This makes it easier to clean up or rotate the secret.
# Using encrypted payload in terraform now triggers a vulnerability by Foundation, so we have to manually save the secret from console.
resource "aws_secretsmanager_secret" "coralogix_query_token" {
  name        = "coralogix-query-token"
  description = "Key used to retrieve metric values from Coralogix"
  kms_key_id  = data.aws_kms_key.wrapidity_key.arn

  force_overwrite_replica_secret = true
}

data "aws_secretsmanager_secret_version" "coralogix_credentials" {
  secret_id = aws_secretsmanager_secret.coralogix_query_token.id
}

resource "kubernetes_secret" "coralogix_query_api_token" {
  metadata {
    name      = "coralogix-query-token"
    namespace = local.kubernetes_namespace
  }
  data = {
    BearerToken = data.aws_secretsmanager_secret_version.coralogix_credentials.secret_string
  }
}

resource "kubernetes_manifest" "coralogix_keda_credential" {
  manifest = {
    "apiVersion" = "keda.sh/v1alpha1"
    "kind"       = "TriggerAuthentication"
    "metadata" = {
      "name"      = "coralogix-keda-credential"
      "namespace" = local.kubernetes_namespace
    }
    "spec" = {
      "secretTargetRef" = [
        {
          "parameter" = "bearerToken"
          "name"      = "coralogix-query-token"
          "key"       = "BearerToken"
        }
      ]
    }
  }
}


resource "kubernetes_manifest" "scaledobject_keda" {
  field_manager {
    force_conflicts = true
  }
  manifest = {
    "apiVersion" = "keda.sh/v1alpha1"
    "kind"       = "ScaledObject"
    "metadata" = {
      "name"      = "${var.browser_farm_name}-scaled-object"
      "namespace" = local.kubernetes_namespace
    }
    "spec" = {
      "maxReplicaCount" = var.max_replicas
      "minReplicaCount" = var.replicas
      "scaleTargetRef" = {
        "name" = var.browser_farm_name
      }
      "cooldownPeriod" = var.scaling_cooldown_period
      "triggers" = [
        {
          "authenticationRef" = {
            "name" = "coralogix-keda-credential"
          }
          "metadata" = {
            authModes     = "bearer"
            metricName    = "browserless_demand"
            query         = "(sum(browserless_running{cx_application_name=\"${local.kubernetes_namespace}\"}) or vector(0)) + (sum(browserless_queued{cx_application_name=\"${local.kubernetes_namespace}\"}) or vector(0))"
            serverAddress = "https://ng-api-http.coralogix.com/metrics"
            threshold     = var.scaling_threshold
          }
          "type" = "prometheus"
        },
      ]
    }
  }
