#https://meltwater.atlassian.net/wiki/spaces/EE/pages/2001931025/Within+AWS+to+other+accounts+or+AWS+Engineering+VPN
locals {
  hostnames_to_enable = var.internal_ingress_enabled ? concat(["${local.service-suffix}-${var.env}-internal.meltwater.io"],var.additional_hostnames) : []
}

resource "kubernetes_ingress" "ingress" {
  count = var.internal_ingress_enabled ? 1 : 0
  metadata {
    annotations = {
      "external-dns.alpha.kubernetes.io/target"            = "${var.namespace}-ingress-internal.meltwater.io"
      "kubernetes.io/ingress.class"                        = var.namespace
      "nginx.ingress.kubernetes.io/proxy-connect-timeout"  = var.nginx_proxy_timeout
      "nginx.ingress.kubernetes.io/proxy-read-timeout"     = var.nginx_proxy_timeout
      "nginx.ingress.kubernetes.io/whitelist-source-range" = var.whitelisted_cidrs
    }
    name = "${local.service-suffix}-ingress"
    namespace = var.namespace
  }

  spec {
    dynamic rule {
      for_each = local.hostnames_to_enable
      content {
        host = rule.value
        http {
          path {
            backend {
              service_name = local.service-suffix
              service_port = 8080
            }
          }
        }
      }
    }
  }
}


resource "kubernetes_service" "service" {
  count = var.internal_ingress_enabled ? 1 : 0
  metadata {
    name = local.service-suffix
    namespace = var.namespace
  }
  spec {
    selector = {
      app = local.service-suffix
    }
    port {
      port        = var.service_port
      target_port = var.service_port
    }
  }
}

output "service_url" {
  value = "${local.service-suffix}-${var.env}-internal.meltwater.io"
}

