  key_id = "alias/wrapidity"
}

resource "aws_iam_user" "iam_user" {
  name = "${var.service_name}_k8s_user"
}

resource "aws_iam_access_key" "key" {
  user = aws_iam_user.iam_user.name
}


data "aws_iam_policy" "news3accesspolicy" {
  name = "NewsBucketAccessPolicy"
}

data "aws_iam_policy" "info3accesspolicy" {
  name = "InfoBucketAccessPolicy"
}

data "aws_iam_policy" "LambdaRole" {
  arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaRole"
}

data "aws_iam_policy"  "AmazonSQSFullAccess" {
  arn = "arn:aws:iam::aws:policy/AmazonSQSFullAccess"
}

resource "aws_iam_user_policy_attachment" "news-attach" {
  count      = var.has_news_access ? 1 : 0
  user       = aws_iam_user.iam_user.name
  policy_arn = data.aws_iam_policy.news3accesspolicy.arn
}

resource "aws_iam_user_policy_attachment" "info-attach" {
  count      = var.has_info_access ? 1 : 0
  user       = aws_iam_user.iam_user.name
  policy_arn = data.aws_iam_policy.info3accesspolicy.arn
}


resource "aws_iam_user_policy_attachment" "lambdas" {
  count      = var.has_lambda_access ? 1 : 0
  user       = aws_iam_user.iam_user.name
  policy_arn = data.aws_iam_policy.LambdaRole.arn
}

output "iam_key" {
  value = aws_iam_access_key.key
}

output "iam_user" {
  value = aws_iam_user.iam_user
}


resource "aws_iam_user_policy_attachment" "sqs" {
  count      = var.has_sqs_access ? 1 : 0
  user       = aws_iam_user.iam_user.name
  policy_arn = data.aws_iam_policy.AmazonSQSFullAccess.arn
}

