# IPA (Induction API) — Boron (EKS) pilot stack.
#
# Sibling of k8s/service/ipa (FKS). This stack deploys induction-api to the Boron
# EKS cluster. The FKS stack (k8s/service/ipa) is left untouched so the existing
# GitHub Actions delivery keeps working until cutover.
#
# The upstream module app.terraform.io/meltwater/wrapidity-deployment/kubernetes
# v1.0.22 produces a deprecated `kubernetes_ingress` (networking.k8s.io/v1beta1,
# removed in k8s 1.22+) and offers no ingressClassName / external-dns / Cilium /
# IRSA knobs, so it CANNOT target Boron (1.35). We therefore hand-roll the
# resources here with the required transformations applied (see deployment.tf).

terraform {

  backend "s3" {
    bucket  = "terraform-state-meltwater-wrapidity-dev"
    key     = "k8s/service/ipa-boron.tfstate"
    region  = "eu-west-1"
    encrypt = true
  }

  required_version = "~> 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 6.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.30"
    }
    tfe = {
      source  = "hashicorp/tfe"
      version = "~> 0.60"
    }
  }
}

# Boron cluster endpoint + CA, read from the Foundation-managed TFE workspace.
# Alternative: the GitHub Actions org vars BORON_K8S_API_SERVER / BORON_K8S_CA_CRT.
data "tfe_outputs" "vpc_boron" {
  organization = "meltwater"
  workspace    = "TFS-Bravo-Aws-Kubernetes-Infrastructure-FKS-Dev-Boron"
}

# Automation auth to Boron via the GHATerraform IAM role -> `aws eks get-token`.
# Requires the kubernetes-infrastructure access PR to be merged first (see README).
provider "kubernetes" {
  host                   = data.tfe_outputs.vpc_boron.values.host
  cluster_ca_certificate = base64decode(data.tfe_outputs.vpc_boron.values.cluster_ca_certificate)
  exec {
    api_version = "client.authentication.k8s.io/v1beta1"
    command     = "aws"
    args        = ["eks", "get-token", "--cluster-name", "boron"]
  }
}

provider "aws" {
  region = var.aws_region
  default_tags {
    tags = merge({
      Name    = "Induction API",
      Service = var.induction_api_name
    }, var.common_tags)
  }
}

