# Data sources for env values. Identical to the FKS stack (k8s/service/ipa):
# all of these live in the wrapidity AWS account, so they are reused verbatim.
# Only the Kubernetes target cluster differs (see terraform.tf).

data "terraform_remote_state" "rds" {
  backend = "s3"
  config = {
    bucket = var.terraform_state_s3_bucket_name
    key    = "aws/${var.aws_region}/database.tfstate"
    region = var.aws_region
  }
}

data "terraform_remote_state" "sitemap_identifier" {
  backend = "s3"
  config = {
    bucket  = var.terraform_state_s3_bucket_name
    key     = "aws/${var.aws_region}/lambda/batch-sitemap_identifier.tfstate"
    region  = "eu-west-1"
    encrypt = "true"
  }
}

data "terraform_remote_state" "rabbit" {
  backend = "s3"
  config = {
    bucket = var.terraform_state_s3_bucket_name
    key    = "aws/${var.aws_region}/mq.tfstate"
    region = var.aws_region
  }
}

data "terraform_remote_state" "sns" {
  backend = "s3"
  config = {
    bucket = var.terraform_state_s3_bucket_name
    key    = "aws/eu-west-1/cluster/batch-request/sns.tfstate"
    region = var.aws_region
  }
}

data "aws_kms_secrets" "rds_secrets" {
  secret {
    name    = "master_password"
    payload = var.rds_password_encrypted
  }
}

data "aws_kms_secrets" "atlas_api_key" {
  secret {
    name    = "atlas_api_key"
    payload = var.atlas_api_key
  }
}

data "aws_secretsmanager_secret_version" "creds" {
  secret_id = "rabbit_credentials"
}

