locals {
  version              = "6.LATEST"
  service              = var.induction_api_name # "induction-api"
  kubernetes_namespace = "${var.team}-${var.env_name}" # "wrapidity-dev" — MUST match FKS for global service
  ecr_repo_base        = "421213061221.dkr.ecr.eu-west-1.amazonaws.com" # matches module default
  image                = "${local.ecr_repo_base}/${local.service}:${local.version}"

  rabbit_creds = jsondecode(data.aws_secretsmanager_secret_version.creds.secret_string)

  # Callers allowed through the internal ingress. The batch-request Lambdas live in
  # the wrapidity VPC (var.vpc_cidr), so that CIDR must stay whitelisted.
  # TODO(confirm): add the Boron pod/node CIDR (10.60.128.0/18) if any in-cluster
  # caller reaches IPA via the ingress rather than the ClusterIP service.
  whitelist_cidrs = join(", ", [var.eng_vpn_cidr, var.vpc_cidr, var.k8s_cidrs[0]])

  # Reproduces the labels the wrapidity-deployment module applies (billing/attribution parity).
  common_labels = {
    app                    = local.service
    MWBilling_CoE          = "FHAIPlatform"
    MWBilling_Environment  = "opex"
    MWBilling_Team         = "wrapidity"
    MWBilling_Department   = "410"
    FHAIPlatform_Component = "CrawlerInduction"
    MWBilling_Product      = "NewsCrawler"
    Contact                = "wrapidity-at-meltwater.com"
    Owner                  = "wrapidity"
    System                 = "pulitzer"
    Env                    = var.k8s_env_name
  }

  # Verbatim from k8s/service/ipa/deployment.tf, MINUS the static AWS_ACCESS_KEY_ID /
  # AWS_SECRET_ACCESS_KEY (replaced by IRSA — see irsa.tf).
  environment_variables = {
    "ENABLE_EXPERIMENTAL_FEATURES"               = "true"
    "FHAI_WRTY_INDUCTION_ATLAS_API_KEY"          = data.aws_kms_secrets.atlas_api_key.plaintext["atlas_api_key"]
    "FHAI_WRTY_INDUCTION_ATLAS_URL"              = "http://${var.atlas_backend_url}"
    "FHAI_WRTY_INDUCTION_CLEANUP_TIME"           = "21:35:01"
    "UNSTUCK_CRON"                               = "0 0 2/6 ? * *"
    "FHAI_WRTY_INDUCTION_DB_HOST"                = element(split(":", data.terraform_remote_state.rds.outputs.rds_endpoint), 0)
    "FHAI_WRTY_INDUCTION_DB_NAME"                = "batch_${var.env_name}_frontier"
    "FHAI_WRTY_INDUCTION_DB_PASSWORD"            = data.aws_kms_secrets.rds_secrets.plaintext["master_password"]
    "FHAI_WRTY_INDUCTION_DB_PORT"                = data.terraform_remote_state.rds.outputs.rds_port
    "FHAI_WRTY_INDUCTION_DB_USERNAME"            = "wrapidity"
    "FHAI_WRTY_INDUCTION_DB_USE_SSL"             = "true"
    "FHAI_WRTY_INDUCTION_INTERNAL_BUCKET"        = "${var.env_name}-batch-frontier-news"
    "FHAI_WRTY_INDUCTION_LOG_LEVEL_API"          = "DEBUG"
    "FHAI_WRTY_INDUCTION_MAX_URLS_PER_SOURCE"    = 10
    "FHAI_WRTY_INDUCTION_RABBIT_HOST"            = data.terraform_remote_state.rabbit.outputs.rabbit_host
    "FHAI_WRTY_INDUCTION_RABBIT_OUTPUT_QUEUE"    = "${var.env_name}-${var.brioche_cache_name}-${var.default_input_queue}"
    "FHAI_WRTY_INDUCTION_RABBIT_PASSWORD"        = local.rabbit_creds[local.service]
    "FHAI_WRTY_INDUCTION_RABBIT_USERNAME"        = "${local.service}-${var.env_name}"
    "FHAI_WRTY_INDUCTION_RABBIT_USE_SSL"         = "true"
    "FHAI_WRTY_INDUCTION_SOURCE_SERVICE"         = "${var.source_service_url}v3/source/config/"
    "FHAI_WRTY_INDUCTION_TOTAL_URLS_TO_SCHEDULE" = 200
    "FHAI_WRTY_INDUCTION_VALIDATE_PATTERNS"      = "false"
    "FHAI_WRTY_NUMBER_OF_DAYS_TO_KEEP"           = "160"
    "LOG4J_FORMAT_MSG_NO_LOOKUPS"                = "true"
    "MANUAL_INDUCTION_RESULT_SNS_ARN"            = data.terraform_remote_state.sns.outputs.induction_results_sns_arn
    "MAX_RAM"                                    = "-Xmx4096M -XX:+UseParallelGC"
    "SERVICE_ADMIN_PORT"                         = var.default_admin_port
    "SERVICE_NAME"                               = var.induction_api_name
    "SERVICE_PORT"                               = var.default_service_port
    "SITEMAP_IDENTIFIER_QUEUE"                   = data.terraform_remote_state.sitemap_identifier.outputs.input_queue_name
  }
}

# ServiceAccount carrying the IRSA role annotation (replaces the static IAM user).
resource "kubernetes_service_account_v1" "ipa" {
  metadata {
    name      = local.service
    namespace = local.kubernetes_namespace
    labels    = local.common_labels
    annotations = {
      "eks.amazonaws.com/role-arn" = aws_iam_role.ipa_irsa.arn
    }
  }
}

resource "kubernetes_deployment_v1" "ipa" {
  metadata {
    name      = local.service
    namespace = local.kubernetes_namespace
    labels    = local.common_labels
  }

  spec {
    # CUTOVER SAFETY: start scaled to zero. Steady-state: 1 (FKS min_replicas = 1).
    # Scale up only after health is validated (see README cutover sequence).
    replicas = 0

    strategy {
      rolling_update {
        max_surge       = 2
        max_unavailable = 0
      }
    }

    selector {
      match_labels = {
        app = local.service
      }
    }

    template {
      metadata {
        labels = local.common_labels
        annotations = {
          "prometheus.io/scrape"         = "true"
          "prometheus.io/path"           = "/metrics"
          "prometheus.io/port"           = "8080"
          "logging.meltwater.io/system"  = "wrty-k8s"
          "logging.meltwater.io/service" = local.service
          "logging.meltwater.io/type"    = "nested_json"
          "harvest"                      = var.k8s_env_name
        }
      }

      spec {
        service_account_name = kubernetes_service_account_v1.ipa.metadata[0].name

        # NODE SELECTION — transformed from the FKS module output.
        # FKS used: toleration dedicated=graviton-c8g8x + nodeSelector
        # foundation.meltwater.io/instance-class=graviton-c8g8x (FKS-only labels).
        # Boron equivalent below targets arm64/Graviton nodes.
        # TODO(foundation/confirm): verify Boron's actual arm64 node label / Karpenter
        # provisioner and whether a nodepool toleration is required before scale-up.
        node_selector = {
          "kubernetes.io/arch" = "arm64"
        }

        affinity {
          pod_anti_affinity {
            preferred_during_scheduling_ignored_during_execution {
              weight = 10
              pod_affinity_term {
                topology_key = "kubernetes.io/hostname"
                label_selector {
                  match_labels = {
                    app = local.service
                  }
                }
              }
            }
          }
        }

        # RDS keystore (enable_rds_keystore_mount = true on FKS).
        # PREREQ: the `rds-certificate-keystore` secret (key keystore.jks) must exist
        # in the Boron wrapidity-dev namespace — mirror k8s/certificates/rds-cert-secret.tf.
        volume {
          name = "secrets"
          secret {
            secret_name = "rds-certificate-keystore"
            items {
              key  = "keystore.jks"
              path = "keystore.jks"
            }
          }
        }

        container {
          name  = local.service
          image = local.image
          # NOTE: the module set no image_pull_secrets — ECR pull relies on node IAM.
          # PREREQ(foundation): Boron node role must be allowed to pull from cross-account
          # ECR 421213061221 (repo policy on induction-api), or the image mirrored.
          image_pull_policy = "Always"

          resources {
            requests = {
              cpu    = "10m"
              memory = "1.3G"
            }
            limits = {
              cpu    = "2"
              memory = "4096M"
            }
          }

          port {
            container_port = 8080
            name           = "service-port"
          }

          volume_mount {
            mount_path = "/mnt/secrets"
            name       = "secrets"
            read_only  = true
          }

          dynamic "env" {
            for_each = local.environment_variables
            content {
              name  = env.key
              value = env.value
            }
          }
        }
      }
    }
  }
}

resource "kubernetes_service_v1" "ipa" {
  metadata {
    name      = local.service
    namespace = local.kubernetes_namespace
    labels    = local.common_labels
    # GLOBAL SERVICE (ClusterMesh) — lets in-cluster callers (delorean,
    # evaluation-framework-api) on FKS reach Boron endpoints during cutover.
    # The FKS IPA Service must carry the SAME two annotations (see README —
    # the module does not expose a service-annotations input).
    annotations = {
      "io.cilium/global-service" = "true"
      "service.cilium.io/global" = "true"
    }
  }
  spec {
    type = "ClusterIP"
    selector = {
      app = local.service
    }
    port {
      port        = 8080
      target_port = 8080
    }
  }
}

resource "kubernetes_ingress_v1" "ipa" {
  metadata {
    name      = "${local.service}-ingress"
    namespace = local.kubernetes_namespace
    labels    = local.common_labels
    annotations = {
      # Internal (VPC/corporate-only) ingress on Boron.
      "external-dns.alpha.kubernetes.io/target"            = "internal-falcon.boron.dev.meltwater.io"
      "nginx.ingress.kubernetes.io/proxy-connect-timeout"  = "300"
      "nginx.ingress.kubernetes.io/proxy-read-timeout"     = "300"
      "nginx.ingress.kubernetes.io/whitelist-source-range" = local.whitelist_cidrs

      # WEIGHTED ROUTING (Phase 4) — uncomment to start the DNS split. The FKS
      # ingress must first be given set-identifier=ew1k8s2 / aws-weight=200 on the
      # SAME hostname. Start Boron low and ramp up.
      # "external-dns.alpha.kubernetes.io/set-identifier" = "boron"
      # "external-dns.alpha.kubernetes.io/aws-weight"     = "25"
    }
  }

  spec {
    ingress_class_name = "nginx"

    rule {
      # SAME hostname as FKS — required for weighted routing and so the Lambdas'
      # INDUCTION_API_HOST (from ipa.tfstate full_service_url) keeps resolving.
      # Covered on Boron by nginx-default-cert (*.meltwater.io) — no ACM annotation.
      host = "${local.service}-${var.env_name}-internal.meltwater.io"
      http {
        path {
          path      = "/"
          path_type = "Prefix"
          backend {
            service {
              name = kubernetes_service_v1.ipa.metadata[0].name
              port {
                number = 8080
              }
            }
          }
        }
      }
    }
  }
}

output "full_service_url" {
  value = "${local.service}-${var.env_name}-internal.meltwater.io"
}

