# IRSA — replaces the static IAM user (k8s/service/ipa/user.tf: module.user +
# ipa_sns_policy). The induction-api ServiceAccount (deployment.tf) assumes this
# role via the Boron cluster OIDC provider. Permissions mirror the FKS user:
#   has_sqs_access  -> AmazonSQSFullAccess
#   has_news_access -> NewsBucketAccessPolicy
#   + SNS:Publish to the induction-results topic (ipa_sns_policy)
#
# CROSS-ACCOUNT NOTE: Boron runs in AWS account 234642166327; the resources IPA
# touches (SNS/SQS/S3-news/RDS) live in the wrapidity account, which is where this
# role is created. For the trust to work, an IAM OIDC identity provider for Boron's
# issuer must be registered in the wrapidity account.
# TODO(foundation/confirm): confirm the Boron OIDC provider is registered in the
# wrapidity account (data lookup below), OR decide to place this role in the Boron
# account instead. Do not apply until this is settled.

locals {
  boron_oidc_issuer = "oidc.eks.eu-west-1.amazonaws.com/id/86F20C107F6321B32C3C7491FB9CE77E"
}

# Boron OIDC provider as registered in the wrapidity account.
data "aws_iam_openid_connect_provider" "boron" {
  url = "https://${local.boron_oidc_issuer}"
}

data "aws_iam_policy_document" "ipa_irsa_trust" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRoleWithWebIdentity"]
    principals {
      type        = "Federated"
      identifiers = [data.aws_iam_openid_connect_provider.boron.arn]
    }
    condition {
      test     = "StringEquals"
      variable = "${local.boron_oidc_issuer}:sub"
      values   = ["system:serviceaccount:${local.kubernetes_namespace}:${local.service}"]
    }
    condition {
      test     = "StringEquals"
      variable = "${local.boron_oidc_issuer}:aud"
      values   = ["sts.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "ipa_irsa" {
  name               = "ipa-boron-irsa"
  description        = "IRSA role for induction-api on Boron (replaces static IAM user)"
  assume_role_policy = data.aws_iam_policy_document.ipa_irsa_trust.json
}

# SNS publish (mirrors ipa_sns_policy in k8s/service/ipa/user.tf).
data "aws_iam_policy_document" "allow_sns_publish" {
  statement {
    actions   = ["SNS:Publish"]
    effect    = "Allow"
    resources = [data.terraform_remote_state.sns.outputs.induction_results_sns_arn]
  }
}

resource "aws_iam_role_policy" "ipa_sns" {
  name   = "ipa-boron-sns-publish"
  role   = aws_iam_role.ipa_irsa.id
  policy = data.aws_iam_policy_document.allow_sns_publish.json
}

# has_sqs_access -> AmazonSQSFullAccess
resource "aws_iam_role_policy_attachment" "sqs" {
  role       = aws_iam_role.ipa_irsa.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSQSFullAccess"
}

# has_news_access -> NewsBucketAccessPolicy (customer-managed policy in the account)
data "aws_iam_policy" "news_access" {
  name = "NewsBucketAccessPolicy"
}

resource "aws_iam_role_policy_attachment" "news" {
  role       = aws_iam_role.ipa_irsa.name
  policy_arn = data.aws_iam_policy.news_access.arn
}

